func runThreadsListLocalFiltered(cmd *cobra.Command, flags *rootFlags, listType, label, participantsFile string, intersectStdin bool, limit int) error {
	if !supportedThreadTypes[listType] {
		return fmt.Errorf("threads list: unsupported --type %q (valid: %s)", listType, strings.Join(validThreadTypes(), ", "))
	}
	if localUnsupportedTypes[listType] {
		return fmt.Errorf("threads list: --type %q cannot be combined with --label / --participants-file / --intersect-with-stdin (the local filter has no negative-label semantics). Drop the local-filter flag to route through Gmail's threads.list, which supports this type natively", listType)
	}
	var participants, threadIDs []string
	if participantsFile != "" {
		emails, err := readParticipantsFile(participantsFile)
		if err != nil {
			return usageErr(err)
		}
		participants = append(participants, emails...)
	}
	if intersectStdin {
		stdinThreads, stdinEmails, err := readThreadIntersection(cmd.InOrStdin())
		if err != nil {
			return usageErr(err)
		}
		threadIDs = append(threadIDs, stdinThreads...)
		participants = append(participants, stdinEmails...)
	}
	acct, err := resolveActiveAccount(flags)
	if err != nil {
		return authErr(fmt.Errorf("threads list local filters: %w", err))
	}
	db, err := store.OpenWithContext(cmd.Context(), defaultDBPath("superhuman-pp-cli"))
	if err != nil {
		return fmt.Errorf("opening local database: %w", err)
	}
	defer db.Close()
	typeLabel := localThreadTypeLabel(listType)
	threads, err := db.ListThreadsFiltered(cmd.Context(), store.ThreadFilter{
		AccountEmail: acct.Email,
		TypeLabel:    typeLabel,
		Label:        label,
		Participants: participants,
		ThreadIDs:    threadIDs,
		Limit:        limit,
	})
	if err != nil {
		return err
	}
	return printJSONFiltered(cmd.OutOrStdout(), map[string]any{
		"action":   "threads.list",
		"resource": "threads",
		"type":     listType,
		"label":    label,
		"success":  true,
		"threads":  threads,
	}, flags)
}

func localThreadTypeLabel(listType string) string {
	switch listType {
	case "inbox":
		return "INBOX"
	case "sent":
		return "SENT"
	case "starred":
		return "STARRED"
	case "spam":
		return "SPAM"
	case "trash":
		return "TRASH"
	case "important":
		return "IMPORTANT"
	case "draft":
		return "DRAFT"
	default:
		return ""
	}
}

// localUnsupportedTypes lists --type values whose semantics ("not in INBOX",
// "everywhere minus INBOX/SENT/SPAM/TRASH") need negative-label filters the
// positive-only local label index cannot express. Combining them with
// --label / --participants-file / --intersect-with-stdin previously dropped
// the type filter silently and returned every local thread that matched the
// other constraints.
var localUnsupportedTypes = map[string]bool{
	"done":     true,
	"archived": true,
}

func readParticipantsFile(path string) ([]string, error) {
	data, err := os.ReadFile(path)
	if err != nil {
		return nil, fmt.Errorf("threads list: read --participants-file %s: %w", path, err)
	}
	text := strings.TrimSpace(string(data))
	if text == "" {
		return nil, nil
	}
	if strings.HasPrefix(text, "[") {
		var emails []string
		if err := json.Unmarshal(data, &emails); err != nil {
			return nil, fmt.Errorf("threads list: parse --participants-file JSON: %w", err)
		}
		return emails, nil
	}
	var emails []string
	for _, line := range strings.Split(text, "\n") {
		line = strings.TrimSpace(line)
		if line != "" {
			emails = append(emails, line)
		}
	}
	return emails, nil
}

func readThreadIntersection(r io.Reader) ([]string, []string, error) {
	data, err := io.ReadAll(r)
	if err != nil {
		return nil, nil, fmt.Errorf("threads list: read stdin: %w", err)
	}
	var threadIDs, emails []string
	for _, line := range strings.Split(strings.TrimSpace(string(data)), "\n") {
		line = strings.TrimSpace(line)
		if line == "" {
			continue
		}
		if strings.Contains(line, "@") {
			emails = append(emails, line)
		} else {
			threadIDs = append(threadIDs, line)
		}
	}
	return threadIDs, emails, nil
}

// runThreadsListGmail is the Gmail-folder branch. Gmail's users.threads.list
// serves inbox, sent, starred, spam, trash, important, and search-query
// derived views such as done/archived. Pagination uses Gmail's pageToken
// contract rather than offset/limit so users can resume a prior listing
// without re-counting.
func validThreadTypes() []string {
	valid := make([]string, 0, len(supportedThreadTypes))
	for k := range supportedThreadTypes {
		valid = append(valid, k)
	}
	sort.Strings(valid)
	return valid
}

func runThreadsListGmail(cmd *cobra.Command, flags *rootFlags, listType string, limit int, pageToken string) error {
	// Verify mode short-circuits before any HTTP fire (per AGENTS.md).
	if cliutil.IsVerifyEnv() {
		fmt.Fprintf(cmd.OutOrStdout(), "would call gmail.googleapis.com/.../threads (%s)\n", listType)
		return nil
	}

	acct, err := resolveActiveAccount(flags)
	if err != nil {
		return authErr(fmt.Errorf("threads list --type inbox: %w", err))
	}
	gc := gmail.New(acct.Store, acct.Email, acct.GoogleID, acct.AccessToken)
	gc.Stderr = cmd.ErrOrStderr()

	spec := gmailThreadListTypes[listType]
	res, err := gc.ListThreads(cmd.Context(), spec.labelIDs, spec.query, limit, pageToken)
	if err != nil {
		if gmail.IsAuth(err) {
			return authErr(fmt.Errorf("threads list --type %s: %w", listType, err))
		}
		if ok, status := gmail.IsAPI(err); ok && status == 404 {
			return notFoundErr(fmt.Errorf("threads list --type %s: %w", listType, err))
		}
		return apiErr(fmt.Errorf("threads list --type %s: %w", listType, err))
	}

	// JSON envelope first — agents read this, humans skip.
	if flags.asJSON || (!isTerminal(cmd.OutOrStdout()) && !flags.csv && !flags.quiet && !flags.plain) {
		if flags.quiet {
			return nil
		}
		threadsJSON := make([]map[string]any, 0, len(res.Threads))
		for _, t := range res.Threads {
			threadsJSON = append(threadsJSON, map[string]any{
				"id":        t.ID,
				"historyId": t.HistoryID,
			})
		}
		envelope := map[string]any{
			"action":               "threads.list",
			"resource":             "threads",
			"type":                 listType,
			"path":                 gmailThreadListPath(spec),
			"success":              true,
			"threads":              threadsJSON,
			"next_page_token":      res.NextPageToken,
			"result_size_estimate": res.ResultSizeEstimate,
		}
		envelopeJSON, jerr := json.Marshal(envelope)
		if jerr != nil {
			return jerr
		}
		return printOutput(cmd.OutOrStdout(), json.RawMessage(envelopeJSON), true)
	}

	// Human-readable: one row per thread + a footer with the page token
	// (when there's more to fetch) so the user can copy-paste.
	if len(res.Threads) == 0 {
		fmt.Fprintf(cmd.OutOrStdout(), "No %s threads.\n", listType)
		return nil
	}
	rows := make([]map[string]any, 0, len(res.Threads))
	for _, t := range res.Threads {
		rows = append(rows, map[string]any{
			"id":        t.ID,
			"historyId": t.HistoryID,
		})
	}
	if perr := printAutoTable(cmd.OutOrStdout(), rows); perr != nil {
		fmt.Fprintf(os.Stderr, "warning: table rendering failed, falling back to plain output: %v\n", perr)
		for _, t := range res.Threads {
			fmt.Fprintf(cmd.OutOrStdout(), "%s\t%s\n", t.ID, t.HistoryID)
		}
	}
	if res.NextPageToken != "" {
		fmt.Fprintf(cmd.OutOrStdout(), "\nMore: --page-token %s\n", res.NextPageToken)
	}
	return nil
}

func gmailThreadListPath(spec threadListGmailSpec) string {
	if len(spec.labelIDs) > 0 {
		return "/users/me/threads?labelIds=" + strings.Join(spec.labelIDs, ",")
	}
	if spec.query != "" {
		return "/users/me/threads?q=" + spec.query
	}
	return "/users/me/threads"
}
